  Widget _buildDailyUsageBar() {
    const maxMinutes = 15;
    final progress = (_todayMinutes / maxMinutes).clamp(0.0, 1.0);
    final color = progress >= 1.0
        ? const Color(0xFFFF6584)
        : progress >= 0.7
            ? const Color(0xFFFFB800)
            : const Color(0xFF43C59E);

    return Container(
      padding: const EdgeInsets.all(20),
      decoration: BoxDecoration(
        gradient: LinearGradient(
          colors: [
            color.withValues(alpha: 0.08),
            color.withValues(alpha: 0.03),
          ],
          begin: Alignment.topLeft,
          end: Alignment.bottomRight,
        ),
        borderRadius: BorderRadius.circular(24),
        border: Border.all(color: color.withValues(alpha: 0.25), width: 1.5),
        boxShadow: [
          BoxShadow(
            color: color.withValues(alpha: 0.03),
            blurRadius: 16,
            offset: const Offset(0, 8),
          ),
        ],
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Container(
                padding: const EdgeInsets.all(8),
                decoration: BoxDecoration(
                  color: color.withValues(alpha: 0.12),
                  shape: BoxShape.circle,
                  border: Border.all(color: color.withValues(alpha: 0.2), width: 1),
                ),
                child: Icon(Icons.timer_outlined, size: 18, color: color),
              ),
              const SizedBox(width: 12),
              Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    'Daily Screen Time',
                    style: TextStyle(
                      fontSize: 12,
                      fontWeight: FontWeight.bold,
                      color: Colors.grey[600],
                      fontFamily: 'Nunito',
                    ),
                  ),
                  Text(
                    '$_todayMinutes / $maxMinutes minutes played',
                    style: const TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.w900,
                      color: Color(0xFF1A1040),
                      fontFamily: 'Nunito',
                    ),
                  ),
                ],
              ),
              const Spacer(),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
                decoration: BoxDecoration(
                  color: progress >= 1.0 ? const Color(0xFFFFEBF0) : const Color(0xFFE8F9F3),
                  borderRadius: BorderRadius.circular(20),
                ),
                child: Text(
                  progress >= 1.0 ? 'Daily Limit Met' : '${maxMinutes - _todayMinutes}m left',
                  style: TextStyle(
                    fontSize: 11,
