  Widget _buildLegacyReportLayout(String text) {
    final lines = text.split('\n');
    final List<Widget> children = [];

    const baseTextStyle = TextStyle(
      fontSize: 14,
      height: 1.6,
      color: Color(0xFF2D2060),
      fontFamily: 'Nunito',
    );
    const boldTextStyle = TextStyle(
      fontSize: 14,
      height: 1.6,
      fontWeight: FontWeight.bold,
      color: Color(0xFF1A1040),
      fontFamily: 'Nunito',
    );

    for (var line in lines) {
      final trimmed = line.trim();
      if (trimmed.isEmpty) continue;

      if (trimmed.startsWith('#') || 
          (trimmed.startsWith('**') && trimmed.endsWith('**') && trimmed.length < 50) ||
          trimmed.contains('Focus Area') ||
          trimmed.contains('Practical Suggestions') ||
          trimmed.contains('Therapist Note') ||
          trimmed.contains('Weekly Summary')) {
        final cleanText = trimmed.replaceAll('**', '').replaceAll('#', '').trim();
        final headerIcon = cleanText.contains('Summary')
            ? '📊'
            : cleanText.contains('CBT')
                ? '🎯'
                : cleanText.contains('Speech') || cleanText.contains('SLP')
                    ? '🗣️'
                    : cleanText.contains('Note')
                        ? '✍️'
                        : '🌟';

        children.add(
          Container(
            width: double.infinity,
            margin: const EdgeInsets.only(top: 20, bottom: 12),
            padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
            decoration: BoxDecoration(
              color: const Color(0xFF6C63FF).withValues(alpha: 0.06),
              borderRadius: BorderRadius.circular(12),
              border: Border.all(color: const Color(0xFF6C63FF).withValues(alpha: 0.12), width: 1),
            ),
            child: Row(
              children: [
                Text(
                  headerIcon,
                  style: const TextStyle(fontSize: 16),
                ),
                const SizedBox(width: 10),
                Expanded(
                  child: Text(
                    cleanText,
                    style: const TextStyle(
                      fontSize: 14,
                      fontWeight: FontWeight.w900,
                      color: Color(0xFF1A1040),
                      fontFamily: 'Nunito',
                    ),
                  ),
                ),
              ],
            ),
          ),
        );
      } else if (trimmed.startsWith('-') || trimmed.startsWith('*')) {
        final cleanText = trimmed.substring(1).trim();
        children.add(
          Padding(
            padding: const EdgeInsets.only(left: 12, bottom: 10),
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                const Padding(
                  padding: EdgeInsets.only(top: 6, right: 10),
                  child: Icon(Icons.circle, size: 6, color: Color(0xFF43C59E)),
                ),
                Expanded(
                  child: RichText(
                    text: TextSpan(
                      children: _parseInlineBold(cleanText, baseTextStyle, boldTextStyle),
                    ),
                  ),
                ),
              ],
            ),
          ),
        );
      } else {
        children.add(
          Padding(
            padding: const EdgeInsets.only(bottom: 14),
            child: RichText(
              text: TextSpan(
                children: _parseInlineBold(trimmed, baseTextStyle, boldTextStyle),
              ),
            ),
          ),
        );
      }
    }

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: children,
    );
  }

  String _sanitizeForPdf(String text) {
    var result = text;
    final Map<String, String> translationMap = {
      'مچھلی': 'Machli', 'گھوڑا': 'Ghoora', 'کتا': 'Kutta', 'بلی': 'Billi',
      'پرندہ': 'Parinda', 'گائے': 'Gaaye', 'ہاتھی': 'Haathi', 'خرگوش': 'Khargosh',
      'تتلی': 'Titli', 'شیر': 'Sher', 'آم': 'Aam', 'روٹی': 'Roti', 'چاول': 'Chawal',
      'پانی': 'Paani', 'سیب': 'Saib', 'کیلا': 'Kela', 'دودھ': 'Doodh', 'انڈا': 'Anda',
      'ڈبل روٹی': 'Double Roti', 'مالٹا': 'Malta', 'امّی': 'Ammi', 'ابّو': 'Abu',
      'دادی': 'Dadi', 'بھائی': 'Bhai', 'بہن': 'Behan', 'دادا': 'Dada', 'بچہ': 'Bachcha',
      'ستارہ': 'Sitara', 'خوش': 'Khush', 'وداس': 'Udaas', 'بھوکا': 'Bhooka',
      'غصہ': 'Gussa', 'ڈرا': 'Dara', 'تھکا': 'Thaka', 'سونا': 'Sona',
      'کھانا': 'Khaana', 'نہانا': 'Nahana', 'کھیلنا': 'Khelna', 'چلنا': 'Chalna',
      'پڑھنا': 'Parhna',
    };
    translationMap.forEach((urdu, roman) {
      result = result.replaceAll(urdu, roman);
    });
    final buffer = StringBuffer();
    for (var i = 0; i < result.length; i++) {
      final charCode = result.codeUnitAt(i);
      if (charCode <= 127 || charCode == 10 || charCode == 13) {
        buffer.write(result[i]);
      } else {
        if (charCode == 8217 || charCode == 8216) {
          buffer.write("'");
        } else if (charCode == 8220 || charCode == 8221) {
          buffer.write('"');
        } else if (charCode == 8211 || charCode == 8212) {
          buffer.write("-");
        }
      }
    }
    return buffer.toString();
  }

  Future<void> _downloadPdf() async {
    if (_report.isEmpty) return;

    final sanitizedReport = _sanitizeForPdf(_report);
    final sanitizedChildName = _sanitizeForPdf(_tracker.childName);
    final doc = pw.Document();
    
    // PDF Inline Bold Parser
    List<pw.TextSpan> parsePdfInlineBold(String text, {PdfColor? textColor}) {
      final parts = text.split('**');
      final List<pw.TextSpan> spans = [];
      for (var i = 0; i < parts.length; i++) {
        if (parts[i].isEmpty) continue;
        spans.add(
          pw.TextSpan(
            text: parts[i],
            style: pw.TextStyle(
              fontSize: 10,
              lineSpacing: 1.5,
              color: textColor ?? PdfColors.grey900,
              fontWeight: (i % 2 == 1) ? pw.FontWeight.bold : pw.FontWeight.normal,
            ),
          ),
        );
      }
      return spans;
    }

    final sections = _parseReportToSections(sanitizedReport);
    final List<pw.Widget> sectionWidgets = [];

    pw.Widget buildPdfSectionCard(String title, String content, PdfColor color) {
      final lines = content.split('\n');
      final List<pw.Widget> listItems = [];

      final hsl = color.toHsl();
      final bgColor = color.shade(1.5 - (0.96 / hsl.lightness));
      final borderColor = color.shade(1.5 - (0.88 / hsl.lightness));
      final textColor = color.shade(1.5 - (0.22 / hsl.lightness));

      for (var line in lines) {
        final trimmed = line.trim();
        if (trimmed.isEmpty) continue;

        if (trimmed.startsWith('-') || trimmed.startsWith('*')) {
          final bulletText = trimmed.substring(1).trim();
          listItems.add(
            pw.Padding(
              padding: const pw.EdgeInsets.only(left: 8, bottom: 4),
              child: pw.Row(
                crossAxisAlignment: pw.CrossAxisAlignment.start,
                children: [
                  pw.Container(
                    margin: const pw.EdgeInsets.only(top: 4, right: 6),
                    width: 4,
                    height: 4,
                    decoration: pw.BoxDecoration(
                      color: textColor,
                      shape: pw.BoxShape.circle,
                    ),
                  ),
                  pw.Expanded(
                    child: pw.RichText(
                      text: pw.TextSpan(
                        children: parsePdfInlineBold(bulletText, textColor: PdfColors.grey900),
                      ),
                    ),
                  ),
                ],
              ),
            ),
          );
        } else {
          listItems.add(
            pw.Padding(
              padding: const pw.EdgeInsets.only(bottom: 6),
              child: pw.RichText(
                text: pw.TextSpan(
                  children: parsePdfInlineBold(trimmed, textColor: PdfColors.grey900),
                ),
              ),
            ),
          );
        }
      }

      return pw.Container(
        width: double.infinity,
        margin: const pw.EdgeInsets.only(bottom: 12),
        padding: const pw.EdgeInsets.all(12),
        decoration: pw.BoxDecoration(
          color: bgColor,
          borderRadius: const pw.BorderRadius.all(pw.Radius.circular(8)),
          border: pw.Border.all(color: borderColor, width: 0.8),
        ),
        child: pw.Column(
          crossAxisAlignment: pw.CrossAxisAlignment.start,
          children: [
            pw.Text(
              title,
              style: pw.TextStyle(
                fontWeight: pw.FontWeight.bold,
                fontSize: 12,
                color: textColor,
              ),
            ),
            pw.SizedBox(height: 8),
            ...listItems,
          ],
        ),
      );
    }

    if (sections.length <= 1) {
      // Legacy simple markdown rendering in PDF
      final lines = sanitizedReport.split('\n');
      for (var line in lines) {
        final trimmed = line.trim();
        if (trimmed.isEmpty) continue;
        if (trimmed.startsWith('#') || trimmed.startsWith('**') && trimmed.endsWith('**') && trimmed.length < 50) {
          sectionWidgets.add(
            pw.Container(
              margin: const pw.EdgeInsets.only(top: 12, bottom: 6),
              child: pw.Text(
                trimmed.replaceAll('**', '').replaceAll('#', '').trim(),
                style: pw.TextStyle(fontWeight: pw.FontWeight.bold, fontSize: 12, color: PdfColors.indigo900),
              ),
            ),
          );
        } else if (trimmed.startsWith('-') || trimmed.startsWith('*')) {
          sectionWidgets.add(
            pw.Padding(
              padding: const pw.EdgeInsets.only(left: 10, bottom: 4),
              child: pw.Row(
                crossAxisAlignment: pw.CrossAxisAlignment.start,
                children: [
                  pw.Container(
                    margin: const pw.EdgeInsets.only(top: 4, right: 6),
                    width: 4,
                    height: 4,
                    decoration: const pw.BoxDecoration(color: PdfColors.grey600, shape: pw.BoxShape.circle),
                  ),
                  pw.Expanded(child: pw.RichText(text: pw.TextSpan(children: parsePdfInlineBold(trimmed.substring(1).trim())))),
                ],
              ),
            ),
          );
        } else {
          sectionWidgets.add(
            pw.Padding(
              padding: const pw.EdgeInsets.only(bottom: 6),
              child: pw.RichText(text: pw.TextSpan(children: parsePdfInlineBold(trimmed))),
            ),
          );
        }
      }
    } else {
      if (sections.containsKey('Executive')) {
        sectionWidgets.add(buildPdfSectionCard('Weekly Clinical Executive Summary', sections['Executive']!, PdfColors.indigo));
      }
      if (sections.containsKey('SLP')) {
        sectionWidgets.add(buildPdfSectionCard('Speech & Language Pathology (SLP) Development', sections['SLP']!, PdfColors.teal));
      }
      if (sections.containsKey('CBT')) {
        sectionWidgets.add(buildPdfSectionCard('Cognitive Behavioral Therapy (CBT) & Emotional Traces', sections['CBT']!, PdfColors.amber));
      }
      if (sections.containsKey('Telemetry')) {
        sectionWidgets.add(buildPdfSectionCard('Systematic Telemetry & Skill Mastery', sections['Telemetry']!, PdfColors.blueGrey));
      }
      if (sections.containsKey('ParentPlan')) {
        sectionWidgets.add(buildPdfSectionCard('Strategic Parent-Led Home Care Plan', sections['ParentPlan']!, PdfColors.teal));
      }
      sections.forEach((key, value) {
        if (key != 'Executive' && key != 'SLP' && key != 'CBT' && key != 'Telemetry' && key != 'ParentPlan' && key != 'Recommendation') {
          sectionWidgets.add(buildPdfSectionCard(key, value, PdfColors.grey));
        }
      });
      if (sections.containsKey('Recommendation')) {
        sectionWidgets.add(buildPdfSectionCard('Therapist Sovereign Recommendation & Note', sections['Recommendation']!, PdfColors.orange));
      }
    }

    // Build stats grid
    final traceCount = _agentService.traceLog.length;
    final adaptations = _agentService.traceLog.expand((t) => t.actions).length;

    doc.addPage(
      pw.MultiPage(
        pageFormat: PdfPageFormat.a4,
        margin: const pw.EdgeInsets.all(32),
        build: (pw.Context context) {
          return [
            // Branded PDF Header
            pw.Row(
              mainAxisAlignment: pw.MainAxisAlignment.spaceBetween,
              children: [
                pw.Column(
                  crossAxisAlignment: pw.CrossAxisAlignment.start,
                  children: [
                    pw.Text(
                      'SITARA CLINICAL REPORT',
                      style: pw.TextStyle(
                        fontSize: 22,
                        fontWeight: pw.FontWeight.bold,
                        color: PdfColors.indigo,
                      ),
                    ),
                    pw.Text(
                      'Progress Guardian Autonomous CBT & SLP Assessment',
                      style: const pw.TextStyle(
                        fontSize: 10,
                        color: PdfColors.grey600,
                      ),
                    ),
                  ],
                ),
                pw.Column(
                  crossAxisAlignment: pw.CrossAxisAlignment.end,
                  children: [
                    pw.Text(
                      'Child: $sanitizedChildName',
                      style: pw.TextStyle(fontWeight: pw.FontWeight.bold, fontSize: 12),
                    ),
                    pw.Text(
                      'Date: ${DateTime.now().toLocal().toString().substring(0, 10)}',
                      style: const pw.TextStyle(fontSize: 9, color: PdfColors.grey600),
                    ),
                  ],
                ),
              ],
            ),
            pw.Divider(color: PdfColors.indigo, thickness: 1.5, height: 16),

            // Dashboard Metrics Summary Card Grid
            pw.Text(
              'WEEKLY ENGAGEMENT TELEMETRY',
              style: pw.TextStyle(fontSize: 9, fontWeight: pw.FontWeight.bold, color: PdfColors.indigo900),
            ),
            pw.SizedBox(height: 6),
            pw.Row(
              children: [
                _buildPdfStatBox('Sessions', '$traceCount', PdfColors.indigo),
                pw.SizedBox(width: 8),
                _buildPdfStatBox('AI Actions', '$adaptations', PdfColors.teal),
                pw.SizedBox(width: 8),
                _buildPdfStatBox('Score', '${_tracker.sessionScore}', PdfColors.amber),
                pw.SizedBox(width: 8),
                _buildPdfStatBox('Streak', 'x${_tracker.bestStreak}', PdfColors.pink),
              ],
            ),
            pw.SizedBox(height: 16),

            // Report Text Cards
            ...sectionWidgets,

            pw.SizedBox(height: 20),
            pw.Divider(color: PdfColors.grey300, thickness: 0.8),
            pw.Row(
              mainAxisAlignment: pw.MainAxisAlignment.spaceBetween,
              children: [
                pw.Text(
                  'Sitara Learning Platform — Google Antigravity Hackathon Submission',
                  style: const pw.TextStyle(fontSize: 8, color: PdfColors.grey500),
                ),
                pw.Text(
                  "Mehnat karein, aap kar saktay hain! Masha'Allah",
                  style: pw.TextStyle(fontSize: 8, fontWeight: pw.FontWeight.bold, color: PdfColors.teal900),
                ),
              ],
            ),
          ];
        },
      ),
    );

    // Save and lay out standard PDF system printer dialogue
    await Printing.layoutPdf(
      onLayout: (PdfPageFormat format) async => doc.save(),
      name: 'Sitara_Weekly_Report_$sanitizedChildName.pdf',
    );
  }

  pw.Widget _buildPdfStatBox(String label, String value, PdfColor color) {
    final hsl = color.toHsl();
    final bgColor = color.shade(1.5 - (0.96 / hsl.lightness));
    final borderColor = color.shade(1.5 - (0.85 / hsl.lightness));
    final textColor = color.shade(1.5 - (0.25 / hsl.lightness));

    return pw.Expanded(
      child: pw.Container(
        padding: const pw.EdgeInsets.all(10),
        decoration: pw.BoxDecoration(
          color: bgColor,
          borderRadius: const pw.BorderRadius.all(pw.Radius.circular(8)),
          border: pw.Border.all(color: borderColor, width: 1),
        ),
        child: pw.Column(
          crossAxisAlignment: pw.CrossAxisAlignment.start,
          children: [
            pw.Text(
              label,
              style: pw.TextStyle(fontSize: 8, color: textColor, fontWeight: pw.FontWeight.bold),
            ),
            pw.SizedBox(height: 4),
            pw.Text(
              value,
              style: pw.TextStyle(fontSize: 16, fontWeight: pw.FontWeight.bold, color: textColor),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildRetentionChips() {
    final retryPct = (_tracker.retryRate * 100).toStringAsFixed(0);
    final churnRisk = _tracker.isChurnRisk;
    final spikeAbandonment = _tracker.hasDifficultySpikeAbandonment;

    return Wrap(
      spacing: 10,
      runSpacing: 10,
      children: [
        _Chip(
          label: 'Retry Rate: $retryPct%',
          color: _tracker.retryRate > 0.5
              ? const Color(0xFFFFB800)
              : const Color(0xFF43C59E),
          icon: Icons.refresh_rounded,
        ),
        _Chip(
          label: churnRisk ? 'Needs Attention' : 'Highly Engaged',
          color: churnRisk ? const Color(0xFFFF6584) : const Color(0xFF43C59E),
          icon: churnRisk
              ? Icons.warning_amber_rounded
              : Icons.check_circle_outline,
        ),
        if (spikeAbandonment)
          const _Chip(
            label: 'Difficulty Spike detected',
            color: Color(0xFFFF6584),
            icon: Icons.trending_down_rounded,
          ),
      ],
    );
  }

  Widget _buildModeComparisonCard() {
    final agentSess = _agentService.agentSessions;
    final baseSess = _agentService.baselineSessions;
    final agentPct =
        (_agentService.agentAvgSuccess * 100).toStringAsFixed(0);
    final basePct =
        (_agentService.baselineAvgSuccess * 100).toStringAsFixed(0);
    final hasBoth = agentSess > 0 && baseSess > 0;
    final delta = hasBoth
        ? _agentService.agentAvgSuccess - _agentService.baselineAvgSuccess
        : null;

    return Container(
      padding: const EdgeInsets.all(24),
      decoration: BoxDecoration(
        color: Colors.white,
        borderRadius: BorderRadius.circular(24),
        border: Border.all(color: const Color(0xFF6C63FF).withValues(alpha: 0.18), width: 1.5),
        boxShadow: [
          BoxShadow(
            color: const Color(0xFF6C63FF).withValues(alpha: 0.05),
            blurRadius: 24,
            offset: const Offset(0, 8),
          )
        ],
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          const Text(
            'Optimization Engine Comparison',
            style: TextStyle(
                fontSize: 15,
                fontWeight: FontWeight.w900,
                color: Color(0xFF1A1040),
                fontFamily: 'Nunito'),
          ),
          const SizedBox(height: 4),
          Text(
            'Success rate comparison between the adaptive AI and static baseline.',
            style: TextStyle(
                fontSize: 12,
                color: Colors.grey[500],
                fontFamily: 'Nunito'),
          ),
          const SizedBox(height: 20),
          _buildModeRow(
            emoji: '🤖',
            label: 'Antigravity Agent (Adaptive AI)',
            sessions: agentSess,
            pct: agentPct,
            color: const Color(0xFF6C63FF),
          ),
          const SizedBox(height: 16),
          _buildModeRow(
            emoji: '📏',
            label: 'Baseline (Fixed Heuristics)',
            sessions: baseSess,
            pct: basePct,
            color: Colors.grey[500]!,
          ),
          if (delta != null) ...[
            const SizedBox(height: 20),
            Container(
              width: double.infinity,
              padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
              decoration: BoxDecoration(
                color: delta >= 0
                    ? const Color(0xFF43C59E).withValues(alpha: 0.1)
                    : Colors.red.withValues(alpha: 0.08),
                borderRadius: BorderRadius.circular(16),
                border: Border.all(
                  color: delta >= 0 ? const Color(0xFF43C59E).withValues(alpha: 0.2) : Colors.red.withValues(alpha: 0.15),
                  width: 1,
                ),
              ),
              child: Text(
                delta >= 0
                    ? '🎉 Adaptive AI is performing ${(delta * 100).toStringAsFixed(0)}% better at matching difficulty!'
                    : 'Collecting more sessions to calibrate comparative telemetry...',
                style: TextStyle(
                  fontSize: 12,
                  fontWeight: FontWeight.bold,
                  color: delta >= 0 ? const Color(0xFF38A381) : Colors.grey,
                  fontFamily: 'Nunito',
                ),
                textAlign: TextAlign.center,
              ),
            ),
          ] else ...[
            const SizedBox(height: 16),
            Text(
              'No comparative data yet — toggle between AI and Heuristic mode in the game play screen to test.',
              style: TextStyle(fontSize: 12, color: Colors.grey[500], fontFamily: 'Nunito', height: 1.4),
              textAlign: TextAlign.center,
            ),
          ],
        ],
      ),
    );
  }

  Widget _buildModeRow({
    required String emoji,
    required String label,
    required int sessions,
    required String pct,
    required Color color,
  }) {
    final successRate = double.tryParse(pct) ?? 0.0;
    final progress = (successRate / 100.0).clamp(0.0, 1.0);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Row(
          children: [
            Container(
              padding: const EdgeInsets.all(6),
              decoration: BoxDecoration(
                color: color.withValues(alpha: 0.1),
                shape: BoxShape.circle,
              ),
              child: Text(emoji, style: const TextStyle(fontSize: 16)),
            ),
            const SizedBox(width: 10),
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    label,
                    style: const TextStyle(
                        fontSize: 13,
                        fontWeight: FontWeight.w900,
                        color: Color(0xFF1A1040),
                        fontFamily: 'Nunito'),
                  ),
                  Text(
                    '$sessions sessions played',
                    style: TextStyle(fontSize: 11, color: Colors.grey[500], fontFamily: 'Nunito'),
                  ),
                ],
              ),
            ),
            const SizedBox(width: 10),
            Text(
              '$pct%',
              style: TextStyle(
                  fontSize: 18,
                  fontWeight: FontWeight.w900,
                  color: color,
                  fontFamily: 'Nunito'),
            ),
          ],
        ),
        const SizedBox(height: 8),
        ClipRRect(
          borderRadius: BorderRadius.circular(6),
          child: LinearProgressIndicator(
            value: progress,
            minHeight: 6,
            backgroundColor: color.withValues(alpha: 0.12),
            valueColor: AlwaysStoppedAnimation<Color>(color),
          ),
        ),
      ],
    );
  }

  String _formatTime(DateTime dt) {
    final h = dt.hour.toString().padLeft(2, '0');
    final m = dt.minute.toString().padLeft(2, '0');
    return '$h:$m';
  }
}

